SELECT count(*) FROM supplier_onboarding

    AND business_name LIKE '%' || #{businessName} || '%'
    AND applicant_name LIKE '%' || #{applicantName} || '%'
    AND business_type = #{businessType}
    AND current_state = #{stateId}

SELECT id, supplier_id as "supplierId", applicant_name as "applicantName", business_name as "businessName", business_type as "businessType", current_state as "stateId", training_progress as "trainingProgress", resubmission_count as "resubmissionCount", submitted_at as "submittedAt", rejection_reason as "rejectionReason" FROM supplier_onboarding
AND business_name LIKE '%' || #{businessName} || '%' AND applicant_name LIKE '%' || #{applicantName} || '%' AND business_type = #{businessType} AND current_state = #{stateId}
ORDER BY ${_sortColumn} ${_sortOrder} LIMIT #{_limit} OFFSET #{_offset}
